CREATE VIEW `dim_apptranslationdb_translation_view` (`server_key` COMMENT "翻译键", `content` COMMENT "内容")
COMMENT "礼券、积分来源渠道source_key值 对应的中文翻译内容获取" AS SELECT `a`.`server_key`, max(`a`.`content`) AS `content`
FROM (SELECT `ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` AS `server_key`, CASE WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'WelfareCenterSignSourceKey') THEN 'H5观看激励视频任务（非网赚版本）' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'BounsWatchAdGetGiftSource') THEN 'H5签到额外奖励' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'SignRewadMsg') THEN 'H5签到' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'BonusCardName') THEN '福利包' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'BonusCardPlusPlus_Name') THEN '新福利包' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'WatchIncentiveVideo') THEN 'H5观看激励视频任务（非网赚版本）' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'BounsWatchAdGetPointSource') THEN 'H5签到额外奖励' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'Plant_Theme4') THEN '种树游戏的签到' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'SignRewadMsg') THEN 'H5签到' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'DigTreasureLotteryCooling') THEN '挖宝人积分抽奖:大冷却位置' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'JiFenLottery') THEN '大转盘抽奖' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'WelfareWatchVideoAward') THEN 'H5福利中心首页激励视频' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'PointsCenterWatchVideoTaskAward') THEN 'H5观看激励视频任务（网赚版本）' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'ExtraWatchVideoTaskAward') THEN 'H5任务额外奖励' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'eatting_dinner') THEN '吃饭任务额外奖励（晚）' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'eatting_breakfast') THEN '吃饭任务额外奖励（早）' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'BookshelfWatchAdTaskAward') THEN '书架顶部激励视频' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'PopupWindowWatchVideoTaskAward') THEN '阅读页弹窗激励视频' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'Plant_Theme2') THEN '种树-偷好友积分' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'Plant_Theme5') THEN '种树-领取在线积分' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'Plant_Theme3') THEN '种树-领取图鉴积分' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'eatting_lunch') THEN '吃饭任务额外奖励（午）' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'TaskAward') THEN 'H5每日任务奖励' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'CenterTaskAwardSourceKey') THEN 'NA化每日任务奖励' WHEN (`ods`.`ods_tidb_apptranslationdb_translation`.`serverkey` = 'Match_tiles_01') THEN '堆叠三消游戏' ELSE `ods`.`ods_tidb_apptranslationdb_translation`.`content` END AS `content`
FROM `ods`.`ods_tidb_apptranslationdb_translation`) `a`
GROUP BY 1;
